    // of auth failures due to Bug 1896350
    switch (httpStatus) {
      case 200:
        mozilla::glean::networking::http_response_status_code.Get("200_ok"_ns)
            .Add(1);
        break;
      case 301:
        mozilla::glean::networking::http_response_status_code
            .Get("301_moved_permanently"_ns)
            .Add(1);
        break;
      case 302:
